INSERT INTO `thesiscapstoneprojects` VALUES('80','Software Engineering Project ','Time Keeping and Payroll System for Integrated ,Manufacturing Services Providers, Inc.','The study aimed to help a company to have an efficient and effective way of monitoring their employee\'s time keeping and payroll system to give a higher quality of service.','Client Based','2018','Amarillas, Bernard Justine C. Balog Jr, Aden R. Juanillo, John Marvin P. ','The system wil be implemented if it reached 100% completion. Site Preparation is at the office of IMSPI. Personnal Training will provide hands-on expirience for the personnel who\'ll have all the access to the system. System Conversion will only be converted if the owner already has decided that theywill be using the ssytem. It will be slowly converted by the Manager who is the one in charge.Data converserion and Implementation Schedule ','','','0');
