INSERT INTO `thesiscapstoneprojects` VALUES('96','System Analysis and Design','Online Doctor Appointment Booking and Hospital Finder System Using Location based Search Algorith ','To design and develop an Online Doctor Appointment Booking and Hospital Finder System using a Location based Search Algothrim. ','Client Based','2017','Villaflores, Jellizza Kelsen Enriquez, Erina Yuki G. Baul, Jaqueline','This is a proper scheduling has to developed by considering all these factors which will increase patient satisfaction. There is time built into the schedule  at the end of the hour to catch up. The scheduling allow to physicians to borrow the unscheduled time from the end of the hour or from patients with less complex problems without having to rush to get back on schedule ','','','0');
